/**
 * Converts a PascalCase or camelCase identifier to kebab-case.
 * e.g. `BlogPost` → `blog-post`, `userProfile` → `user-profile`
 */
export function toKebabCase(name: string): string {
  return name
    .replace(/([A-Z])/g, (match, letter: string, offset: number) =>
      offset === 0 ? letter.toLowerCase() : `-${letter.toLowerCase()}`,
    )
    .toLowerCase()
}

const IRREGULAR_PLURALS: Record<string, string> = {
  person: 'people',
  man: 'men',
  woman: 'women',
  child: 'children',
  tooth: 'teeth',
  foot: 'feet',
  mouse: 'mice',
  goose: 'geese',
}

/**
 * Produces a simple English plural for a word.
 * Covers the most common inflection rules; irregular forms are handled via a
 * small lookup table.
 */
export function pluralize(word: string): string {
  const lower = word.toLowerCase()

  if (IRREGULAR_PLURALS[lower]) {
    return IRREGULAR_PLURALS[lower]
  }

  if (/(?:s|x|z|ch|sh)$/.test(lower)) {
    return `${word}es`
  }

  if (/[^aeiou]y$/.test(lower)) {
    return `${word.slice(0, -1)}ies`
  }

  if (/(?:f|fe)$/.test(lower)) {
    return `${word.replace(/(?:f|fe)$/, '')}ves`
  }

  return `${word}s`
}

/**
 * Returns the REST resource path segment for a model name.
 * e.g. `BlogPost` → `/blog-posts`, `User` → `/users`
 */
export function resourcePath(modelName: string): string {
  return `/${pluralize(toKebabCase(modelName))}`
}

/**
 * Returns the camelCase property name used on the root `RestApiClient` for a
 * given model, e.g. `BlogPost` → `blogPost`, `User` → `user`.
 */
export function clientPropertyName(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1)
}

