import type * as DMMF from '@prisma/dmmf'

import { fieldToTsType } from './type-mapper'

/** Generates a `export enum` declaration for a DMMF enum. */
export function buildEnumDeclaration(dmmfEnum: DMMF.DatamodelEnum): string {
  const members = dmmfEnum.values.map((v) => `  ${v.name} = '${v.name}'`).join(',\n')
  return `export enum ${dmmfEnum.name} {\n${members},\n}`
}

/**
 * Generates the primary TypeScript interface for a model.
 *
 * Scalar and enum fields are always included. Relation fields are included as
 * optional properties so that API responses that eagerly load relations are
 * still assignable to this type.
 */
export function buildModelInterface(model: DMMF.Model): string {
  const lines: string[] = []

  for (const field of model.fields) {
    if (field.kind === 'object') {
      // Relations are optional because REST endpoints may or may not include them.
      const type = field.isList ? `${field.type}[]` : `${field.type} | null`
      lines.push(`  ${field.name}?: ${type}`)
    } else {
      const optional = !field.isRequired ? '?' : ''
      lines.push(`  ${field.name}${optional}: ${fieldToTsType(field)}`)
    }
  }

  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Generates a `*CreateInput` interface for a model.
 *
 * Fields that are read-only (e.g. `@default`, `@updatedAt`, `@id` auto-
 * increments) or are relation objects are omitted. Fields that have a default
 * value or are optional in the schema are typed as optional here too.
 */
export function buildCreateInputInterface(model: DMMF.Model): string {
  const lines: string[] = []

  for (const field of model.fields) {
    if (field.kind === 'object') continue
    if (field.isReadOnly) continue

    const optional = !field.isRequired || field.hasDefaultValue ? '?' : ''
    lines.push(`  ${field.name}${optional}: ${fieldToTsType(field)}`)
  }

  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates a `*UpdateInput` interface for a model.
 * All writable scalar/enum fields are typed as optional partial updates.
 */
export function buildUpdateInputInterface(model: DMMF.Model): string {
  const lines: string[] = []

  for (const field of model.fields) {
    if (field.kind === 'object') continue
    if (field.isReadOnly) continue

    lines.push(`  ${field.name}?: ${fieldToTsType(field)}`)
  }

  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates a `*WhereInput` interface for a model used in `findMany` filters.
 * All non-relation fields are optional.
 */
export function buildWhereInputInterface(model: DMMF.Model): string {
  const lines: string[] = []

  for (const field of model.fields) {
    if (field.kind === 'object') continue
    lines.push(`  ${field.name}?: ${fieldToTsType(field)}`)
  }

  return `export interface ${model.name}WhereInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates a `*WhereUniqueInput` interface for a model.
 * Only `@id` and `@unique` fields are included because those are the only
 * fields that can uniquely identify a single record.
 */
export function buildWhereUniqueInputInterface(model: DMMF.Model): string {
  const lines: string[] = []

  for (const field of model.fields) {
    if (field.kind === 'object') continue
    if (!field.isId && !field.isUnique) continue
    lines.push(`  ${field.name}?: ${fieldToTsType(field)}`)
  }

  return `export interface ${model.name}WhereUniqueInput {\n${lines.join('\n')}\n}`
}

