import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'
import { describe, expect, it } from 'vitest'

import { generateRestClientCode } from '../generate-client'
import { buildEnumDeclaration, buildModelInterface, buildWhereUniqueInputInterface } from '../interface-builder'
import { buildModelClientClass } from '../model-client-builder'
import { clientPropertyName, pluralize, resourcePath, toKebabCase } from '../naming'
import { fieldToTsType, mapScalarType } from '../type-mapper'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as DMMF.Model
}

function makeGeneratorOptions(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): GeneratorOptions {
  return {
    generator: {
      name: 'restClient',
      provider: { fromEnvVar: null, value: 'prisma-generator-rest-client' },
      output: { fromEnvVar: null, value: '/tmp/generated' },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/tmp/schema.prisma',
    },
    otherGenerators: [],
    schemaPath: '/tmp/schema.prisma',
    datamodel: '',
    version: 'test',
    datasources: [],
    dmmf: {
      datamodel: {
        models,
        enums,
        types: [],
        indexes: [],
      },
      schema: { inputObjectTypes: {}, outputObjectTypes: {}, enumTypes: {} } as never,
      mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
    },
  }
}

// ---------------------------------------------------------------------------
// type-mapper
// ---------------------------------------------------------------------------

describe('mapScalarType', () => {
  it.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['Decimal', 'number'],
    ['BigInt', 'bigint'],
    ['DateTime', 'string'],
    ['Json', 'unknown'],
    ['Bytes', 'string'],
    ['UnknownCustom', 'unknown'],
  ])('maps %s → %s', (prisma, ts) => {
    expect(mapScalarType(prisma)).toBe(ts)
  })
})

describe('fieldToTsType', () => {
  it('handles list fields', () => {
    const field = makeField({ name: 'tags', type: 'String', isList: true })
    expect(fieldToTsType(field)).toBe('string[]')
  })

  it('handles enum fields', () => {
    const field = makeField({ name: 'role', type: 'Role', kind: 'enum' } as Partial<DMMF.Field> & {
      name: string
      type: string
    })
    expect(fieldToTsType(field)).toBe('Role')
  })

  it('handles relation fields', () => {
    const field = makeField({ name: 'author', type: 'User', kind: 'object' } as Partial<DMMF.Field> & {
      name: string
      type: string
    })
    expect(fieldToTsType(field)).toBe('User')
  })
})

// ---------------------------------------------------------------------------
// naming
// ---------------------------------------------------------------------------

describe('toKebabCase', () => {
  it.each([
    ['User', 'user'],
    ['BlogPost', 'blog-post'],
    ['userProfile', 'user-profile'],
    ['APIKey', 'a-p-i-key'],
  ])('converts %s → %s', (input, expected) => {
    expect(toKebabCase(input)).toBe(expected)
  })
})

describe('pluralize', () => {
  it.each([
    ['user', 'users'],
    ['post', 'posts'],
    ['category', 'categories'],
    ['box', 'boxes'],
    ['leaf', 'leaves'],
    ['person', 'people'],
  ])('pluralizes %s → %s', (word, expected) => {
    expect(pluralize(word)).toBe(expected)
  })
})

describe('resourcePath', () => {
  it('produces a kebab-plural resource path', () => {
    expect(resourcePath('BlogPost')).toBe('/blog-posts')
    expect(resourcePath('User')).toBe('/users')
    expect(resourcePath('Category')).toBe('/categories')
  })
})

describe('clientPropertyName', () => {
  it('lowercases the first character', () => {
    expect(clientPropertyName('User')).toBe('user')
    expect(clientPropertyName('BlogPost')).toBe('blogPost')
  })
})

// ---------------------------------------------------------------------------
// interface-builder
// ---------------------------------------------------------------------------

describe('buildEnumDeclaration', () => {
  it('generates a TypeScript enum', () => {
    const dmmfEnum: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [
        { name: 'USER', dbName: null },
        { name: 'ADMIN', dbName: null },
      ],
    }
    const result = buildEnumDeclaration(dmmfEnum)
    expect(result).toContain('export enum Role')
    expect(result).toContain("USER = 'USER'")
    expect(result).toContain("ADMIN = 'ADMIN'")
  })
})

describe('buildModelInterface', () => {
  it('includes scalar fields with required/optional markers', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, isReadOnly: true, hasDefaultValue: true }),
      makeField({ name: 'name', type: 'String' }),
      makeField({ name: 'bio', type: 'String', isRequired: false }),
    ])
    const result = buildModelInterface(model)
    expect(result).toContain('export interface User')
    expect(result).toContain('id: number')
    expect(result).toContain('name: string')
    expect(result).toContain('bio?: string')
  })

  it('includes relation fields as optional', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'author', type: 'User', kind: 'object' } as Partial<DMMF.Field> & {
        name: string
        type: string
      }),
    ])
    const result = buildModelInterface(model)
    expect(result).toContain('author?: User | null')
  })
})

describe('buildWhereUniqueInputInterface', () => {
  it('only includes @id and @unique fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'email', type: 'String', isUnique: true }),
      makeField({ name: 'name', type: 'String' }),
    ])
    const result = buildWhereUniqueInputInterface(model)
    expect(result).toContain('id?: number')
    expect(result).toContain('email?: string')
    expect(result).not.toContain('name')
  })
})

// ---------------------------------------------------------------------------
// model-client-builder
// ---------------------------------------------------------------------------

describe('buildModelClientClass', () => {
  const userModel = makeModel('User', [
    makeField({ name: 'id', type: 'Int', isId: true }),
    makeField({ name: 'email', type: 'String', isUnique: true }),
    makeField({ name: 'name', type: 'String' }),
  ])

  it('uses the @id field for URL segments', () => {
    const result = buildModelClientClass(userModel)
    expect(result).toContain('params.where.id')
  })

  it('generates all five CRUD methods', () => {
    const result = buildModelClientClass(userModel)
