import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'
import { describe, expect, it } from 'vitest'

import { generateRestClientCode } from '../generate-client'
import { buildEnumDeclaration, buildModelInterface, buildWhereUniqueInputInterface } from '../interface-builder'
import { buildModelClientClass } from '../model-client-builder'
import { clientPropertyName, pluralize, resourcePath, toKebabCase } from '../naming'
import { fieldToTsType, mapScalarType } from '../type-mapper'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as DMMF.Model
}

function makeGeneratorOptions(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): GeneratorOptions {
  return {
    generator: {
      name: 'restClient',
      provider: { fromEnvVar: null, value: 'prisma-generator-rest-client' },
      output: { fromEnvVar: null, value: '/tmp/generated' },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/tmp/schema.prisma',
    },
    otherGenerators: [],
    schemaPath: '/tmp/schema.prisma',
    datamodel: '',
    version: 'test',
    datasources: [],
    dmmf: {
      datamodel: {
        models,
        enums,
        types: [],
        indexes: [],
      },
      schema: { inputObjectTypes: {}, outputObjectTypes: {}, enumTypes: {} } as never,
      mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
    },
  }
}

