// type-mapper
// ---------------------------------------------------------------------------

describe('mapScalarType', () => {
  it.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['Decimal', 'number'],
    ['BigInt', 'bigint'],
    ['DateTime', 'string'],
    ['Json', 'unknown'],
    ['Bytes', 'string'],
    ['UnknownCustom', 'unknown'],
  ])('maps %s → %s', (prisma, ts) => {
    expect(mapScalarType(prisma)).toBe(ts)
  })
})

describe('fieldToTsType', () => {
  it('handles list fields', () => {
    const field = makeField({ name: 'tags', type: 'String', isList: true })
    expect(fieldToTsType(field)).toBe('string[]')
  })

  it('handles enum fields', () => {
    const field = makeField({ name: 'role', type: 'Role', kind: 'enum' } as Partial<DMMF.Field> & {
      name: string
      type: string
    })
    expect(fieldToTsType(field)).toBe('Role')
  })

  it('handles relation fields', () => {
    const field = makeField({ name: 'author', type: 'User', kind: 'object' } as Partial<DMMF.Field> & {
      name: string
      type: string
    })
    expect(fieldToTsType(field)).toBe('User')
  })
})

// ---------------------------------------------------------------------------
// naming
// ---------------------------------------------------------------------------

describe('toKebabCase', () => {
  it.each([
    ['User', 'user'],
    ['BlogPost', 'blog-post'],
    ['userProfile', 'user-profile'],
    ['APIKey', 'a-p-i-key'],
  ])('converts %s → %s', (input, expected) => {
    expect(toKebabCase(input)).toBe(expected)
  })
})

describe('pluralize', () => {
  it.each([
    ['user', 'users'],
    ['post', 'posts'],
    ['category', 'categories'],
    ['box', 'boxes'],
    ['leaf', 'leaves'],
    ['person', 'people'],
  ])('pluralizes %s → %s', (word, expected) => {
    expect(pluralize(word)).toBe(expected)
  })
})

describe('resourcePath', () => {
  it('produces a kebab-plural resource path', () => {
    expect(resourcePath('BlogPost')).toBe('/blog-posts')
    expect(resourcePath('User')).toBe('/users')
    expect(resourcePath('Category')).toBe('/categories')
  })
})

describe('clientPropertyName', () => {
  it('lowercases the first character', () => {
    expect(clientPropertyName('User')).toBe('user')
    expect(clientPropertyName('BlogPost')).toBe('blogPost')
  })
})

